#include <bits/stdc++.h>
using namespace std;
int main(){
    int n,k,p;
    cin>>n>>k;
    int a[k],b[k][n/k];
    for (int i=0;i<k;i++){
        cin>>a[i];
    }
    for (int i=0;i<k;i++){
        p=0;
        for (int j=0;j<n/k;j++){
            cin>>b[i][j];
            for (int l=0;l<k;l++){
                if (b[i][j]==a[l]){
                    p++;
                }
            }
        }
        if (p!=1) break;
    }
    if (p!=1) cout<<"\\QAQ/";
    else cout<<"\"MiaoW\"";
    return 0;
}
